      Value *Zero = ConstantInt::get(InitBool->getValueType(), 0);
      Value *NewCI;
      switch (ICI->getPredicate()) {
      default: llvm_unreachable("Unknown ICmp Predicate!");
      case ICmpInst::ICMP_EQ:
      case ICmpInst::ICMP_ULE:
        NewCI = Builder.CreateICmpEQ(LV, Zero);
        break;
      case ICmpInst::ICMP_NE:
      case ICmpInst::ICMP_UGT:
        NewCI = Builder.CreateICmpNE(LV, Zero);
        break;
      }
      ICI->replaceAllUsesWith(NewCI);
```
This seems correct. It handles both `EQ` and `NE` style comparisons by creating a new `ICmpInst` that produces an `i1`.

I will use `cat <<'EOF' > patch.txt` and then `patch` to apply this multi-line change.

```bash
cat <<'EOF' > patch.txt
--- a/llvm/lib/Transforms/IPO/GlobalOpt.cpp
+++ b/llvm/lib/Transforms/IPO/GlobalOpt.cpp
@@ -1005,18 +1005,21 @@
                                      "g.init.val");
       InitBoolUsed = true;

+      // Convert the loaded i8 value to an i1 by comparing with zero.
+      Value *Zero = ConstantInt::get(InitBool->getValueType(), 0);
+      Value *NewCI;
       switch (ICI->getPredicate()) {
       default: llvm_unreachable("Unknown ICmp Predicate!");
       case ICmpInst::ICMP_EQ:
       case ICmpInst::ICMP_ULE:
-        break;
+        NewCI = Builder.CreateICmpEQ(LV, Zero);
+        break;
       case ICmpInst::ICMP_NE:
       case ICmpInst::ICMP_UGT:
-        // The result of the comparison is the inverted value of the bool.
-        LV = Builder.CreateNot(LV);
+        NewCI = Builder.CreateICmpNE(LV, Zero);
         break;
       }
-      ICI->replaceAllUsesWith(LV);
+      ICI->replaceAllUsesWith(NewCI);
       ICI->eraseFromParent();
     }
     LI->eraseFromParent();
EOF
patch -p1 < patch.txt
```

